mapper.select:
select
	t1.id                             ,
	t1.zcdj                           ,
	t1.last_update_date               ,
	t1.cjgzrq                         ,
	t1.szbm                           ,
	t1.csd                            ,
	t1.jrbdwsj                        ,
	t1.whcd                           ,
	t1.rylb                           ,
	t1.created_dept                   ,
	t1.sfqy                           ,
	t1.last_update_ip                 ,
	t1.created_by                     ,
	t1.last_updated_by                ,
	t1.sfzh                           ,
	t1.jylb                           ,
	t1.creation_date                  ,
	t1.jtzz                           ,
	t1.jndj                           ,
	t1.zc                             ,
	t1.xb                             ,
	t1.jtygbm                         ,
	t1.mz                             ,
	t1.sflb                           ,
	t1.csrq                           ,
	t1.szgw                           ,
	t1.rybm                           ,
	t1.xm                             ,
	t1.yjbm                           ,
	t1.version                        ,
	t1.org_identity                   ,
	t1.jg                             ,
	t1.nl  ,
       t1.ryid
from dyn_mdm_ry 	t1


			and t1.ID =#{id}


			and t1.ZCDJ =#{zcdj}


			and t1.LAST_UPDATE_DATE =#{lastUpdateDate}


			and t1.CJGZRQ =#{cjgzrq}


			and t1.SZBM =#{szbm}


			and t1.CSD =#{csd}


			and t1.JRBDWSJ =#{jrbdwsj}


			and t1.WHCD =#{whcd}


			and t1.RYLB =#{rylb}


			and t1.CREATED_DEPT =#{createdDept}


			and t1.SFQY =#{sfqy}


			and t1.LAST_UPDATE_IP =#{lastUpdateIp}


			and t1.CREATED_BY =#{createdBy}


			and t1.LAST_UPDATED_BY =#{lastUpdatedBy}


			and t1.SFZH =#{sfzh}


			and t1.JYLB =#{jylb}


			and t1.CREATION_DATE =#{creationDate}


			and t1.JTZZ =#{jtzz}


			and t1.JNDJ =#{jndj}


			and t1.ZC =#{zc}


			and t1.XB =#{xb}


			and t1.JTYGBM =#{jtygbm}


			and t1.MZ =#{mz}


			and t1.SFLB =#{sflb}


			and t1.CSRQ >= #{csrqBegin}


			and t1.CSRQ <= #{csrqEnd}


			and t1.SZGW =#{szgw}


			and t1.RYBM =#{rybm}


			and t1.XM =#{xm}


			and t1.YJBM =#{yjbm}


			and t1.VERSION =#{version}


			and t1.ORG_IDENTITY =#{orgIdentity}


			and t1.JG =#{jg}


			and t1.NL =#{nl}


			and t1.RYID =#{ryid}
